solution_code:
#include <stdio.h>
#include <stddef.h>
typedef struct {
    char a;
    int b;
    char c;
    double d;
    char e;
} Padded;
typedef struct {
    double d;
    int b;
    char a;
    char c;
    char e;
} Packed;
size_t padded_sizeof(void) { return sizeof(Padded); }
size_t packed_sizeof(void) { return sizeof(Packed); }
size_t padded_offsetof_a(void) { return offsetof(Padded, a); }
size_t padded_offsetof_b(void) { return offsetof(Padded, b); }
size_t padded_offsetof_d(void) { return offsetof(Padded, d); }
size_t packed_offsetof_d(void) { return offsetof(Packed, d); }
size_t packed_offsetof_b(void) { return offsetof(Packed, b); }
size_t packed_offsetof_a(void) { return offsetof(Packed, a); }

validation.test_code:
void test_padded_size(void) {
    TEST_ASSERT_EQUAL_INT(32, (int)padded_sizeof());
}

void test_packed_size(void) {
    TEST_ASSERT_EQUAL_INT(16, (int)packed_sizeof());
}

void test_padded_offsets(void) {
    TEST_ASSERT_EQUAL_INT(0, (int)padded_offsetof_a());
    TEST_ASSERT_EQUAL_INT(4, (int)padded_offsetof_b());
    TEST_ASSERT_EQUAL_INT(16, (int)padded_offsetof_d());
}

void test_packed_offsets(void) {
    TEST_ASSERT_EQUAL_INT(0, (int)packed_offsetof_d());
    TEST_ASSERT_EQUAL_INT(8, (int)packed_offsetof_b());
    TEST_ASSERT_EQUAL_INT(12, (int)packed_offsetof_a());
}

int main(void) {
    RUN_TEST(test_padded_size);
    RUN_TEST(test_packed_size);
    RUN_TEST(test_padded_offsets);
    RUN_TEST(test_packed_offsets);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

